--- 三消小游戏 对象

local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LMatchThreeGameObj:LxNodeBase
local LMatchThreeGameObj = LxClass("LMatchThreeGameObj", LxNodeBase)

local CS                 = CS
local LxResPathUtil           = LxResPathUtil
local ObjType            = ModelMatchThreeGame.ObjType
local Tweening           = DG.Tweening
local Ease               = LxUnity.YXTweeningEase

-- 怪物图标路径
local MonsterIconPath    = "connectionMiniGame_snakeIcon_monster"
local MonsterOnIconPath  = "connectionMiniGame_snakeIcon_monster_on"

-- 炸弹图标路径
local BombPathList       = {
    "connectionMiniGame_organ_301",
    "connectionMiniGame_organ_302",
}

-- 地洞图标路径
local BurrowIconPath     = "connectionMiniGame_organ_201"

-- 箱子图标路径
local BoxPathList        = {
    "connectionMiniGame_organ_101",
    "connectionMiniGame_organ_102",
    "connectionMiniGame_organ_103",
    "connectionMiniGame_organ_104",
}

-- 正常图标路径 （对应相应的类型）
local NormalIconPathMap  = {
    [1] = "connectionMiniGame_snakeIcon_1",
    [2] = "connectionMiniGame_snakeIcon_2",
    [3] = "connectionMiniGame_snakeIcon_3",
    [4] = "connectionMiniGame_snakeIcon_4",
}
local HightIconPath      = "connectionMiniGame_snakeIcon_on"

function LMatchThreeGameObj:LMatchThreeGameObj(ctrl)
    -- LBlockMiniGameObjsCtrl
    self._ctrl = ctrl
    self._objType = 0


    -- 当前血量
    self._curHp = 1
    -- 怪物血量列表 （地洞才有）
    self._monsterHpList = {}
    -- 地洞时，当剩余怪物数量为n时，刷新怪物
    self._refreshWhenNum = 0
    -- 地洞时，怪物优先级
    self._monsterPriority = 0
end

-- 销毁
function LMatchThreeGameObj:Destroy()

    self:ClearAllAnim()

    if self._ctrl:IsDestroy() then
        LxUnity.Destroy(self._uiData.transform)
    else
        if self._effObj then
            LxUnity.DestroyObject(self._effObj)
            self._effObj = nil
        end
        self._ctrl:GetCtrl("ObjsPool"):RecycleObj(self._uiData)
    end

    local tab = self._effObjList or {}
    LxTimer.DelayTimeCall(function()
        for _, obj in ipairs(tab) do
            LxUnity.DestroyObject(obj)
        end
    end, 1)

    LxNodeBase.Dispose(self)

    self._isDestroy = true
end

-- 销毁
function LMatchThreeGameObj:IsDestroy()
    return self._isDestroy
end

-- 清理所有动画
function LMatchThreeGameObj:ClearAllAnim()
    if self._dropSeq then
        self._dropSeq:Kill(false)
        self._dropSeq = nil
    end
    self:Shake(false)
    self:StopJump()
    self:StopJumpAndScale()
    self:StopPlayDead()
end

-- 初始化
function LMatchThreeGameObj:Init(param)
    self._parent = param.parent
    self._uiData = param.uiData
    self._objType = param.objType
    self._uiData.transform:SetParent(self._parent, false)

    self:SetIndex(param.index)
    self:SetPos(param.pos)
    self:InitEff()
    self:ShowEff(false)
end

-- 初始化特效
function LMatchThreeGameObj:InitEff()
    local mgr = self._ctrl:GetMgr()
    local effsPool = mgr:GetCtrl("EffsPool")

    local effName
    if self:IsMonster() then
        effName = "fx_ui_lianxian_haipa"
    elseif self:IsNormal() then
        effName = "fx_ui_lianxian_baonu"
    end

    local function LoadEnd(originalObj)
        if self:IsDestroy() then
            return
        end

        local obj = LxUnity.InstantObject(originalObj)
        local trans = obj.transform
        trans:SetParent(self._uiData.eff, false)
        trans.localPosition = Vector3(0, 0, 0)
        CS.ShowObject(trans, true)
        self._effObj = obj
    end
    if not effName then
        return
    end

    effsPool:LoadEffObj(effName, LoadEnd)
end

-- 显示/隐藏特效
function LMatchThreeGameObj:ShowEff(isShow)
    CS.ShowObject(self._uiData.eff, isShow)
end

-- 获取transform
function LMatchThreeGameObj:GetTransform()
    return self._uiData.transform
end

-- 显示/隐藏对象
function LMatchThreeGameObj:ShowObj(isShow)
    CS.ShowObject(self._uiData.gameObject, isShow)
end

-- 获取类型
function LMatchThreeGameObj:GetType()
    return self._objType
end

-- 设置位置
function LMatchThreeGameObj:SetPos(pos)
    self._pos = pos
    self._uiData.transform.position = pos
end

-- 获取位置
function LMatchThreeGameObj:GetPos()
    return self._pos
end

-- 设置索引
function LMatchThreeGameObj:SetIndex(index)
    self._index = index
end

-- 获取索引
function LMatchThreeGameObj:GetIndex()
    return self._index
end

-- 初始化UI
function LMatchThreeGameObj:Refresh()
    self:RefreshEmpty()

    self:ClearAllAnim()

    if self:IsEmpty() then
        return
    end

    local isMonster = self:IsMonster()
    local iconPath = ""
    local order = 10
    if isMonster then
        iconPath = MonsterIconPath
        order = 100
    elseif self:IsBomb() then
        local curHp = self:GetHp()
        if curHp > #BombPathList then
            iconPath = BombPathList[#BombPathList]
        else
            iconPath = BombPathList[curHp] or BombPathList[1]
        end
        order = 200
    elseif self:IsBox() then
        local curHp = self:GetHp()
        if curHp > #BoxPathList then
            iconPath = BoxPathList[#BoxPathList]
        else
            iconPath = BoxPathList[curHp] or BoxPathList[1]
        end
    elseif self:IsBurrow() then
        iconPath = BurrowIconPath
    elseif self:IsNormal() then
        iconPath = NormalIconPathMap[self._objType]
    end

    self._uiData.iconSprite.sortingOrder = order

    CS.ShowObject(self._uiData.bg, false)
    CS.ShowObject(self._uiData.icon, true)
    --LxResPathUtil.SetSceneSprite(self._uiData.icon, self._uiData.icon, iconPath)
    self:SetSpriteRenderer(self._uiData.icon, iconPath)

    CS.ShowObject(self._uiData.hpBg, isMonster)
    if isMonster then
        local curHp          = self:GetHp()
        curHp                = math.max(curHp, 0)
        self._uiData.hp.text = curHp
    end
end

-- 刷新空白
function LMatchThreeGameObj:RefreshEmpty()
    CS.ShowObject(self._uiData.bg, true)
    CS.ShowObject(self._uiData.eff, false)
    CS.ShowObject(self._uiData.icon, false)

    self._uiData.transform.localScale = Vector3.one
end

-- ture:为正常图标
function LMatchThreeGameObj:IsNormal()
    return self._objType < ObjType.Empty
end

-- ture:为空白
function LMatchThreeGameObj:IsEmpty()
    return self._objType == ObjType.Empty
end

-- ture:为怪物
function LMatchThreeGameObj:IsMonster()
    return self._objType == ObjType.Monster
end

-- ture:为炸弹
function LMatchThreeGameObj:IsBomb()
    return self._objType == ObjType.Bomb
end

-- ture:为箱子
function LMatchThreeGameObj:IsBox()
    return self._objType == ObjType.Box
end

-- ture:为地洞
function LMatchThreeGameObj:IsBurrow()
    return self._objType == ObjType.Burrow
end

-- 设置当前血量
function LMatchThreeGameObj:SetHp(hp)
    self._curHp = hp
end

-- 获取当前血量
function LMatchThreeGameObj:GetHp()
    return self._curHp
end

-- 设置怪物血量列表
function LMatchThreeGameObj:SetMonsterHpList(hpList)
    self._monsterHpList = hpList
end

-- 获取怪物血量列表
function LMatchThreeGameObj:GetMonsterHpList()
    return self._monsterHpList
end

-- 设置怪物优先级
function LMatchThreeGameObj:SetMonsterPriority(priority)
    self._monsterPriority = priority
end

-- 获取怪物优先级
function LMatchThreeGameObj:GetMonsterPriority()
    return self._monsterPriority
end

-- 设置怪物血量列表
function LMatchThreeGameObj:SetMonsterRefreshWhenNum(refreshWhenNum)
    self._refreshWhenNum = refreshWhenNum
end

-- 地洞时，当剩余怪物数量为n时，刷新怪物
function LMatchThreeGameObj:GetMonsterRefreshWhenNum()
    return self._refreshWhenNum
end

-- 弹出怪物血量 (返回nil表示已没有怪物)
function LMatchThreeGameObj:PopMonsterHp(num)
    if self:GetMonsterRefreshWhenNum() >= num then
        return table.remove(self._monsterHpList, 1)
    end
    return nil
end

-- 死亡动画
function LMatchThreeGameObj:PlayDead(time, endFunc, delayTime)
    self:ClearAllAnim()

    time = time or 0.35
    delayTime = delayTime or 0

    local trans = self._uiData.transform
    local tw = trans:DOScale(0, time)
    local seq = Tweening.DOTween.Sequence()
    if self:IsBomb() then
        tw:OnStart(function()
            self:PlayBombEff()
        end)
    end
    seq:Insert(delayTime, tw)
    if self:IsBomb() then
        seq:InsertCallback(0.3, function() end)
    end
    seq:SetAutoKill(true)
    seq:OnComplete(function()
        self._playDeadSeq = nil
        if self:IsDestroy() then
            return
        end
        local func = self._playDeadEndFunc
        self._playDeadEndFunc = nil
        if func then
            func()
        end
        if endFunc then
            endFunc()
        end
        self:Destroy()
    end)
    seq:Play()
    self._playDeadSeq = seq
    self._ctrl:DeleteObj(self._index)
end

-- 播放炸弹特效
function LMatchThreeGameObj:PlayBombEff()
    local mgr = self._ctrl:GetMgr()
    local effsPool = mgr:GetCtrl("EffsPool")

    local function LoadEnd(originalObj)
        if self:IsDestroy() then
            return
        end

        local obj = LxUnity.InstantObject(originalObj)
        local trans = obj.transform
        trans:SetParent(self._uiData.transform.parent, false)
        trans.position = self._uiData.transform.position
        CS.ShowObject(trans, true)

        self._effObjList = self._effObjList or {}
        table.insert(self._effObjList, obj)
        gLGameAudio:PlaySoundByRefId(364)
    end

    effsPool:LoadEffObj("fx_ui_lianxian_boom", LoadEnd)
    LNativeHelper.Vibrate()
end

-- 停止死亡动画
function LMatchThreeGameObj:StopPlayDead()
    if self._playDeadSeq then
        self._playDeadSeq:Kill(false)
        self._playDeadSeq = nil

        self:Destroy()
    end
end

-- 改变血量, hurtType: 0:普通 1:炸弹伤害; inConnectClear:true表示在连接消除范围
function LMatchThreeGameObj:ChangeHp(connectNum, hurtType, inConnectClear)
    local hp = self:GetHp()
    if self:IsNormal() then
        hp = 0
    elseif self:IsMonster() then
        local curHp = self:GetHp()
        if hurtType == 0 then
            hp = curHp - connectNum
        else
            if inConnectClear then
                hp = curHp - connectNum * 2
            else
                hp = curHp - connectNum
            end
        end
    elseif self:IsBox() then
        local curHp = self:GetHp()
        hp = curHp - 1
    elseif self:IsBomb() then
        local curHp = self:GetHp()
        hp = curHp - 1
    end
    self:SetHp(hp)
end

-- 设置死亡动画结束回调
function LMatchThreeGameObj:SetPlayDeadEndFunc(func)
    self._playDeadEndFunc = func
end

-- 可怜的怪物
function LMatchThreeGameObj:ShowSadMonsterIcon()
    self:ShowEff(false)
    if not self:IsMonster() then
        return
    end
    --LxResPathUtil.SetSceneSprite(self._uiData.icon, self._uiData.icon, MonsterOnIconPath)
    self:SetSpriteRenderer(self._uiData.icon, MonsterOnIconPath)
    self:ShowEff(true)
end

-- 播放正常连线状态
function LMatchThreeGameObj:PlayNormalWhenConnect()
    self:Shake(true)

    self:ShowEff(false)
    local iconPath = NormalIconPathMap[self._objType]
    --LxResPathUtil.SetSceneSprite(self._uiData.icon, self._uiData.icon, iconPath)
    self:SetSpriteRenderer(self._uiData.icon, iconPath)
end

-- 播放多消连线状态
function LMatchThreeGameObj:PlayHeightWhenConnect()
    self:Shake(true)
    self:ShowEff(true)
    --LxResPathUtil.SetSceneSprite(self._uiData.icon, self._uiData.icon, HightIconPath)
    self:SetSpriteRenderer(self._uiData.icon, HightIconPath)
end

-- 震动
function LMatchThreeGameObj:Shake(isRun)
    if not isRun then
        if self._shakeTw then
            self._shakeTw:Kill(false)
            self._shakeTw = nil

            local trans = self._uiData.root
            trans.localPosition = Vector3(0, 0, 0)
        end
        return
    end
    if self._shakeTw then
        return
    end

    local trans = self._uiData.root
    trans.localPosition = Vector3(0, 0, 0)
    local shakeTw = trans:DOShakePosition(0.5, 0.08)
    shakeTw:SetLoops(-1)
    shakeTw:Play()
    self._shakeTw = shakeTw
end

-- 设置下落的路径
function LMatchThreeGameObj:SetDropPathList(path)
    self._dropPathList = path
end

-- 获取下落的路径
function LMatchThreeGameObj:GetDropPathList()
    return self._dropPathList
end

-- 下落
function LMatchThreeGameObj:DropDown(delay, oneDropNodeTime, endFunc)
    local path = self._dropPathList
    self._dropPathList = nil
    if path == nil or #path == 0 then
        endFunc()
        return
    end

    local trans = self._uiData.transform
    local posCtrl = self._ctrl:GetCtrl("Pos")
    local seqMove = Tweening.DOTween.Sequence()
    local fisrtIndex = table.remove(path, 1)

    seqMove:AppendInterval(delay)
    seqMove:AppendCallback(function()
        if self:IsDestroy() then
            return
        end
        self:ShowObj(true)
        local pos = posCtrl:GetPosByIndex(fisrtIndex)
        trans.position = pos
    end)

    for _, index in ipairs(path) do
        local toPos = posCtrl:GetPosByIndex(index)
        local moveTw = trans:DOMove(toPos, oneDropNodeTime)
        moveTw:SetEase(Ease.Linear)
        seqMove:Append(moveTw)
    end

    seqMove:Play()
    seqMove:OnComplete(function()
        if self:IsDestroy() then
            return
        end

        self._dropSeq = nil
        endFunc()
    end)
    self._dropSeq = seqMove
end

-- 跳到相应格子
function LMatchThreeGameObj:JumpTo(index, duration, endFunc)
    local posCtrl = self._ctrl:GetCtrl("Pos")
    local pos = posCtrl:GetPosByIndex(index)


    local trans = self._uiData.transform
    duration = duration or 0.5
    local tw = trans:DOJump(pos, 0.1, 1, duration)
    tw:OnComplete(function()
        if self:IsDestroy() then
            return
        end

        self._jumpTw = nil
        if endFunc then
            endFunc()
        end
    end)
    tw:Play()
    self._jumpTw = tw
end

-- 停止跳动
function LMatchThreeGameObj:StopJump()
    if self._jumpTw then
        self._jumpTw:Kill(false)
        self._jumpTw = nil
    end
end

-- 跳并缩放到相应格子
function LMatchThreeGameObj:JumpAndScaleTo(index, duration, endFunc)
    local posCtrl = self._ctrl:GetCtrl("Pos")
    local pos = posCtrl:GetPosByIndex(index)


    local trans = self._uiData.transform
    duration = duration or 0.5
    local tw1 = trans:DOJump(pos, 0.1, 1, duration)
    local tw2 = trans:DOScale(1, duration)

    local seq = Tweening.DOTween.Sequence()
    seq:Insert(0, tw1)
    seq:Insert(0, tw2)

    seq:OnComplete(function()
        if self:IsDestroy() then
            return
        end

        self._jumpAndScaleTw = nil
        if endFunc then
            endFunc()
        end
    end)
    seq:Play()
    self._jumpAndScaleTw = seq
end

-- 停止跳动
function LMatchThreeGameObj:StopJumpAndScale()
    if self._jumpAndScaleTw then
        self._jumpAndScaleTw:Kill(false)
        self._jumpAndScaleTw = nil
    end
end

return LMatchThreeGameObj
